using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup()
    {
        _cart = new ShoppingCart();
    }

    // --- AddItem Tests ---

    [TestMethod]
    public void AddItem_SingleItem_DoesNotThrow()
    {
        _cart.AddItem("SKU-001", 1, 9.99m);
    }

    [TestMethod]
    public void AddItem_MultipleItems_AllContributeToTotal()
    {
        _cart.AddItem("SKU-001", 2, 5.00m);
        _cart.AddItem("SKU-002", 1, 3.00m);

        var total = _cart.CalculateTotal();

        Assert.AreEqual(13.00m, total);
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_CombinesQuantity()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-001", 2, 10.00m);

        var total = _cart.CalculateTotal();

        Assert.AreEqual(30.00m, total);
    }

    [TestMethod]
    public void AddItem_ZeroQuantity_DoesNotAffectTotal()
    {
        _cart.AddItem("SKU-001", 0, 10.00m);

        var total = _cart.CalculateTotal();

        Assert.AreEqual(0m, total);
    }

    [TestMethod]
    public void AddItem_NullSku_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(() =>
            _cart.AddItem(null!, 1, 10.00m));
    }

    [TestMethod]
    public void AddItem_NegativeQuantity_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(() =>
            _cart.AddItem("SKU-001", -1, 10.00m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(() =>
            _cart.AddItem("SKU-001", 1, -5.00m));
    }

    // --- RemoveItem Tests ---

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromCart()
    {
        _cart.AddItem("SKU-001", 2, 5.00m);
        _cart.RemoveItem("SKU-001");

        var total = _cart.CalculateTotal();

        Assert.AreEqual(0m, total);
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(() =>
            _cart.RemoveItem("SKU-MISSING"));
    }

    [TestMethod]
    public void RemoveItem_OneOfMultipleItems_OnlyRemovesThatItem()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-002", 1, 20.00m);

        _cart.RemoveItem("SKU-001");

        var total = _cart.CalculateTotal();
        Assert.AreEqual(20.00m, total);
    }

    // --- CalculateTotal Tests ---

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        var total = _cart.CalculateTotal();

        Assert.AreEqual(0m, total);
    }

    [TestMethod]
    public void CalculateTotal_MultipleItemsVariousQuantities_ReturnsCorrectSum()
    {
        _cart.AddItem("A", 3, 2.50m);
        _cart.AddItem("B", 1, 7.00m);
        _cart.AddItem("C", 2, 4.25m);

        var total = _cart.CalculateTotal();

        Assert.AreEqual(22.00m, total);
    }

    // --- ApplyCoupon Tests ---

    [TestMethod]
    public void ApplyCoupon_ValidCode_ReducesTotal()
    {
        _cart.AddItem("SKU-001", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");

        var total = _cart.CalculateTotal();

        Assert.IsTrue(total < 100.00m, "Total should be reduced after applying coupon.");
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(() =>
            _cart.ApplyCoupon("INVALID"));
    }

    [TestMethod]
    public void ApplyCoupon_NullCode_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(() =>
            _cart.ApplyCoupon(null!));
    }

    [TestMethod]
    public void ApplyCoupon_EmptyCode_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(() =>
            _cart.ApplyCoupon(""));
    }

    [TestMethod]
    public void ApplyCoupon_AppliedToEmptyCart_TotalRemainsZero()
    {
        _cart.ApplyCoupon("SAVE10");

        var total = _cart.CalculateTotal();

        Assert.AreEqual(0m, total);
    }

    // --- Integration / Combined Behavior ---

    [TestMethod]
    public void AddThenRemoveThenRecalculate_TotalIsCorrect()
    {
        _cart.AddItem("SKU-001", 2, 15.00m);
        _cart.AddItem("SKU-002", 1, 25.00m);
        _cart.RemoveItem("SKU-001");

        var total = _cart.CalculateTotal();

        Assert.AreEqual(25.00m, total);
    }

    [TestMethod]
    public void ApplyCouponThenAddItem_CouponStillApplies()
    {
        _cart.AddItem("SKU-001", 1, 50.00m);
        _cart.ApplyCoupon("SAVE10");
        _cart.AddItem("SKU-002", 1, 50.00m);

        var total = _cart.CalculateTotal();

        Assert.IsTrue(total < 100.00m, "Coupon should still reduce total after adding more items.");
    }
}

